        lines.append("# HELP up 1 if the service is up.")
        lines.append("# TYPE up gauge")
        lines.append(f"up {up}")
        lines.append("# HELP process_uptime_seconds Uptime in seconds.")
        lines.append("# TYPE process_uptime_seconds gauge")
        lines.append(f"process_uptime_seconds {uptime:.3f}")
        lines.append("# HELP http_requests_total Total HTTP requests received.")
        lines.append("# TYPE http_requests_total counter")
